class Solution:
    def groupAnagrams(self, strs: list[str]) -> list[list[str]]:
        groups = defaultdict(list)  # signature -> [words]
        for s in strs:
            key = ''.join(sorted(s))  # sorted string is the anagram signature
            groups[key].append(s)
        return list(groups.values())

