class Solution:
    def isValidSudoku(self, board: list[list[str]]) -> bool:
        rows = defaultdict(set)     # rows[r] = set of digits in row r
        cols = defaultdict(set)     # cols[c] = set of digits in col c
        boxes = defaultdict(set)    # boxes[(r//3, c//3)] = set of digits in that box

        for r in range(9):
            for c in range(9):
                if board[r][c] == '.':
                    continue
                digit = board[r][c]
                box = (r // 3, c // 3)

                if digit in rows[r] or digit in cols[c] or digit in boxes[box]:
                    return False

                rows[r].add(digit)
                cols[c].add(digit)
                boxes[box].add(digit)

        return True

class Codec:
    def encode(self, strs: list[str]) -> str:
        """Encodes a list of strings to a single string."""
        return ''.join(f"{len(s)}#{s}" for s in strs)

    def decode(self, s: str) -> list[str]:
        """Decodes a single string to a list of strings."""
        result = []
        i = 0
        while i < len(s):
            # find the delimiter '#'
            j = i
            while s[j] != '#':
                j += 1
            length = int(s[i:j])   # parse the length
            # extract the string of that length
            result.append(s[j + 1 : j + 1 + length])
            i = j + 1 + length     # move past this string
        return result

class Solution:
    def longestConsecutive(self, nums: list[int]) -> int:
        if not nums:
            return 0
        nums = sorted(set(nums))  # remove duplicates and sort
        longest = 1
        current = 1
        for i in range(1, len(nums)):
            if nums[i] == nums[i - 1] + 1:
                current += 1
            else:
                longest = max(longest, current)
                current = 1
        return max(longest, current)

class Solution:
    def longestConsecutive(self, nums: list[int]) -> int:
        num_set = set(nums)
        longest = 0

        for num in num_set:
            # only start a sequence if num is the beginning (num-1 not present)
            if num - 1 not in num_set:
                current_num = num
                current_streak = 1

                while current_num + 1 in num_set:
                    current_num += 1
                    current_streak += 1

                longest = max(longest, current_streak)

        return longest

class Solution:
    def longestConsecutive(self, nums: list[int]) -> int:
        if not nums:
            return 0

        parent = {}  # parent[x] = parent of x
        size = {}    # size[root] = size of component

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])  # path compression
            return parent[x]

        def union(x, y):
            root_x, root_y = find(x), find(y)
            if root_x == root_y:
                return
            # union by size
            if size[root_x] < size[root_y]:
                root_x, root_y = root_y, root_x
            parent[root_y] = root_x
            size[root_x] += size[root_y]

        # initialize each number as its own component
        for num in nums:
            if num not in parent:
                parent[num] = num
                size[num] = 1

        # union consecutive numbers
        for num in nums:
            if num + 1 in parent:
                union(num, num + 1)

        return max(size.values())

