import math

def repeatedStringMatch(a, b):
    lenA = len(a)
    lenB = len(b)
    minMult = math.ceil(lenB/lenA)
    if rabinKarp(a*minMult, b):
        return minMult
    if rabinKarp(a*(minMult+1), b):
        return minMult+1
    return -1

